if (!MIDDLE_PLAN || MIDDLE_PLAN.length !== AUTHORED_MIDDLE_RECORDS.length) {
  throw new TypeError('Middle archive content must match the twenty-slot canonical plan.');
}

function materialize(spec, index) {
  const slot = MIDDLE_PLAN[index];
  return {
    id: slot.id,
    sequence: slot.sequence,
    chapterId: slot.chapterId,
    unlockAfterBeatId: slot.unlockAfterBeatId,
    title: spec.title,
    recordType: spec.recordType,
    custodian: spec.custodian,
    accessNote: spec.accessNote,
    paragraphs: spec.paragraphs,
  };
}

export const ARCHIVE_RECORDS_MIDDLE = deepFreeze(AUTHORED_MIDDLE_RECORDS.map(materialize));

const validation = validateArchiveRecordPack(ARCHIVE_RECORDS_MIDDLE, { expectedGroup: 'middle' });
if (!validation.ok) {
  throw new TypeError(`Invalid middle archive record pack:\n${validation.errors.join('\n')}`);
}

export const ARCHIVE_RECORDS_MIDDLE_METRICS = validation.metrics;
